messages.content:
{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Validate and parse the command string to determine the operation type.",
      "behavior": "Check command is one of 'place', 'cancel', 'track'. Return parsed command type or error.",
      "boundary": {
        "in_scope": [
          "command validation",
          "command type extraction"
        ],
        "out_of_scope": [
          "order data validation",
          "execution of any operation"
        ]
      },
      "semantic_inputs": [
        {
          "name": "command",
          "description": "Order command string",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "parsed_command",
          "description": "Validated command type",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is a string"
      ],
      "postconditions": [
        "parsed_command is one of 'place', 'cancel', 'track' or error"
      ],
      "guarantees": [
        "Returns error if command invalid"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "PlaceOrder",
      "purpose": "Execute the full place order workflow: validate items, charge payment, reserve inventory, create order, send notification.",
      "behavior": "Sequentially validate items stock, charge payment, reserve inventory, create order record, send confirmation. On any failure, rollback previous steps.",
      "boundary": {
        "in_scope": [
          "item validation",
          "payment charging",
          "inventory reservation",
          "order creation",
          "notification sending",
          "rollback on failure"
        ],
        "out_of_scope": [
          "order cancellation",
          "order tracking"
        ]
      },
      "semantic_inputs": [
        {
          "name": "order_data",
          "description": "Order payload with items, payment_method, shipping_address",
          "source": "parent input"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        },
        {
          "name": "inventory",
          "description": "Inventory database",
          "source": "internal leaf access"
        },
        {
          "name": "payments",
          "description": "Payments database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result with success, order_id, status, message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "parsed_command is 'place'",
        "order_data contains items, payment_method, shipping_address"
      ],
      "postconditions": [
        "If success: order created, payment charged, inventory reserved, notification sent. If failure: all changes rolled back."
      ],
      "guarantees": [
        "Atomicity: all or nothing"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CancelOrder",
      "purpose": "Execute the cancel order workflow: verify order exists and not shipped, refund payment, restore inventory, update order status.",
      "behavior": "Check order exists and status allows cancellation, refund payment, restore reserved inventory, update order status to cancelled. Rollback on failure.",
      "boundary": {
        "in_scope": [
          "order existence check",
          "shipped status check",
          "payment refund",
          "inventory restoration",
          "order status update"
        ],
        "out_of_scope": [
          "order placement",
          "order tracking"
        ]
      },
      "semantic_inputs": [
        {
          "name": "order_data",
          "description": "Order payload with order_id",
          "source": "parent input"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        },
        {
          "name": "inventory",
          "description": "Inventory database",
          "source": "internal leaf access"
        },
        {
          "name": "payments",
          "description": "Payments database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result with success, order_id, status, message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "parsed_command is 'cancel'",
        "order_data contains order_id"
      ],
      "postconditions": [
        "If success: order cancelled, payment refunded, inventory restored. If failure: no changes."
      ],
      "guarantees": [
        "Cannot cancel shipped order",
        "Atomicity"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "TrackOrder",
      "purpose": "Return current order status and estimated delivery time.",
      "behavior": "Look up order by order_id, retrieve status and estimated delivery, return result.",
      "boundary": {
        "in_scope": [
          "order lookup",
          "status retrieval",
          "delivery time estimation"
        ],
        "out_of_scope": [
          "order modification",
          "payment processing"
        ]
      },
      "semantic_inputs": [
        {
          "name": "order_data",
          "description": "Order payload with order_id",
          "source": "parent input"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result with success, order_id, status, message (including delivery time)",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "parsed_command is 'track'",
        "order_data contains order_id"
      ],
      "postconditions": [
        "Order status and delivery time returned"
      ],
      "guarantees": [
        "Read-only operation, no side effects"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The parent OrderSystem function is decomposed into four children: ParseCommand validates the command, and three command-specific children (PlaceOrder, CancelOrder, TrackOrder) handle each operation. This keeps each child focused on a single workflow, with the parent acting as the router. No sibling calls exist; the parent invokes the appropriate child based on parsed command.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "ParseCommand",
      "data": "command",
      "note": "Validate command type"
    },
    {
      "from": "ParseCommand",
      "to": "parent",
      "data": "parsed_command",
      "note": "Return parsed command"
    },
    {
      "from": "parent",
      "to": "PlaceOrder",
      "data": "order_data",
      "note": "If command is 'place'"
    },
    {
      "from": "parent",
      "to": "CancelOrder",
      "data": "order_data",
      "note": "If command is 'cancel'"
    },
    {
      "from": "parent",
      "to": "TrackOrder",
      "data": "order_data",
      "note": "If command is 'track'"
    },
    {
      "from": "PlaceOrder",
      "to": "parent",
      "data": "order_result",
      "note": "Return result"
    },
    {
      "from": "CancelOrder",
      "to": "parent",
      "data": "order_result",
      "note": "Return result"
    },
    {
      "from": "TrackOrder",
      "to": "parent",
      "data": "order_result",
      "note": "Return result"
    }
  ]
}
